1	export type Customer = {
2	  yearsWithMHPCO: number;
3	};
4	
5	export type Item = {
6	  type: string;
7	  material?: string;
8	  cursed?: boolean;
9	  enchantment?: number;
10	};
11	
12	export type QuoteStep = {
13	  op: "quote";
14	  items: Item[];
15	};
16	
