51	const PROCESSING_FEE = 5;
52	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
53	const CURSE_SURCHARGE_RATE = 0.5;
54	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
55	const HIGH_ENCHANTMENT_MINIMUM = 5;
56	const LOYALTY_DISCOUNT_RATE = 0.2;
57	const LOYALTY_MINIMUM_YEARS = 2;
58	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
59	
60	const BASE_PREMIUMS: Record<string, number> = {
61	  sword: 100,
62	  amulet: 60,
63	  staff: 80,
64	  potion: 40,
65	  rune: 25,
66	  moonstone: 25,
67	};
68	
69	const COMPONENT_BLOCK_SIZE = 3;
70	const COMPONENT_BLOCK_PREMIUM = 60;
71	
72	const countByType = (items: Item[]): Map<string, number> => {
73	  const counts = new Map<string, number>();
74	  for (const item of items) {
75	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
76	  }
77	  return counts;
78	};
79	
80	const groupBasePremium = (type: string, count: number): number =>
81	  count === COMPONENT_BLOCK_SIZE
82	    ? COMPONENT_BLOCK_PREMIUM
83	    : count * BASE_PREMIUMS[type];
84	
85	const sumBy = <T>(values: T[], amount: (value: T) => number): number =>
86	  values.reduce((total, value) => total + amount(value), 0);
87	
88	const computeBasePremium = (items: Item[]): number =>
89	  sumBy([...countByType(items)], ([type, count]) =>
90	    groupBasePremium(type, count),
91	  );
92	
93	const itemCurseSurcharge = (item: Item): number =>
94	  item.cursed ? BASE_PREMIUMS[item.type] * CURSE_SURCHARGE_RATE : 0;
95	
96	const enchantmentOf = (item: Item): number => item.enchantment ?? 0;
97	
98	const itemHighEnchantmentSurcharge = (item: Item): number =>
99	  enchantmentOf(item) >= HIGH_ENCHANTMENT_MINIMUM
100	    ? BASE_PREMIUMS[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE
101	    : 0;
102	
103	const quotePremium = (
104	  customer: Customer,
105	  items: Item[],
106	  isFollowUp: boolean,
107	): number => {
108	  const basePremium = computeBasePremium(items);
109	  const curseSurcharge = sumBy(items, itemCurseSurcharge);
110	  const highEnchantmentSurcharge = sumBy(items, itemHighEnchantmentSurcharge);
111	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
112	  const loyaltyDiscount =
113	    customer.yearsWithMHPCO >= LOYALTY_MINIMUM_YEARS
114	      ? basePremium * LOYALTY_DISCOUNT_RATE
115	      : 0;
116	  const followUpDiscount = isFollowUp
117	    ? basePremium * FOLLOW_UP_DISCOUNT_RATE
118	    : 0;
119	  const exactPremium =
120	    basePremium +
121	    curseSurcharge +
122	    highEnchantmentSurcharge +
123	    firstInsuranceSurcharge -
124	    loyaltyDiscount -
125	    followUpDiscount +
126	    PROCESSING_FEE;
127	  return Math.ceil(exactPremium);
128	};
129	
130	const DEDUCTIBLE = 100;
131	const PAYOUT_CAP_MULTIPLIER = 2;
132	const HALF_REIMBURSEMENT_MINIMUM_ENCHANTMENT = 8;
133	const HALF_REIMBURSEMENT_RATE = 0.5;
134	
135	const INSURANCE_VALUES: Record<string, number> = {
136	  sword: 1000,
137	  amulet: 600,
138	  rune: 250,
139	};
140	
141	const insuranceValueOf = (item: Item): number => INSURANCE_VALUES[item.type];
142	
143	const reimbursementFor = (insuredItem: Item, damage: Damage): number =>
144	  enchantmentOf(insuredItem) >= HALF_REIMBURSEMENT_MINIMUM_ENCHANTMENT
145	    ? damage.amount * HALF_REIMBURSEMENT_RATE
146	    : damage.amount;
147	
148	const findInsuredItem = (insuredItems: Item[], damage: Damage): Item =>
149	  insuredItems.find((item) => item.type === damage.itemType) as Item;
150	
151	const damagePayout = (insuredItems: Item[], damage: Damage): number =>
152	  reimbursementFor(findInsuredItem(insuredItems, damage), damage) - DEDUCTIBLE;
153	
154	const settleClaim = (
155	  insuredItems: Item[],
156	  damages: Damage[],
157	  remainingCap: number,
158	): ClaimResult => {
159	  const desiredPayout = sumBy(damages, (damage) =>
160	    damagePayout(insuredItems, damage),
161	  );
162	  const payout = Math.min(desiredPayout, remainingCap);
163	  return { payout, remainingCap: remainingCap - payout };
164	};
165	
166	const policyOf = (scenario: Scenario, claim: ClaimStep): QuoteStep =>
167	  scenario.steps[claim.policy] as QuoteStep;
168	
169	const initialCapOf = (policy: QuoteStep): number =>
170	  PAYOUT_CAP_MULTIPLIER * sumBy(policy.items, insuranceValueOf);
171	
172	export const processScenario = (scenario: Scenario): { results: Result[] } => {
173	  const remainingCaps = new Map<number, number>();
174	  return {
175	    results: scenario.steps.map((step, index) => {
176	      if (step.op === "quote") {
177	        return { premium: quotePremium(scenario.customer, step.items, index > 0) };
178	      }
179	      const policy = policyOf(scenario, step);
180	      const remainingCap =
181	        remainingCaps.get(step.policy) ?? initialCapOf(policy);
182	      const result = settleClaim(
183	        policy.items,
184	        step.incident.damages,
185	        remainingCap,
186	      );
187	      remainingCaps.set(step.policy, result.remainingCap);
188	      return result;
189	    }),
190	  };
191	};
